INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 2002, 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 126401, -470.0, 0.0, 1.47, 2, "2023/09/22 14:59:59", 1, 10001, "2023/06/30 12:00:00", "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 2002, 2, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 126401, -470.0, 0.0, 2.15, 1, "2023/09/22 14:59:59", 2, 10002, "2023/06/30 12:00:00", "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 2002, 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 126501, -470.0, 0.0, 0.0, 2, "2023/09/22 14:59:59", 2, 10003, "2023/06/30 12:00:00", "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 2002, 2, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 126501, -470.0, 0.0, 0.0, 1, "2023/09/22 14:59:59", 1, 10004, "2023/06/30 12:00:00", "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 2002, 1, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 127702, -470.0, 0.0, 0.0, 2, "2023/12/22 14:59:59", 2, 10005, "2023/09/15 15:00:00", "リンド");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 2002, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 127702, -470.0, 0.0, 0.0, 2, "2023/12/22 14:59:59", 2, 10006, "2023/09/15 15:00:00", "リンド");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 2002, 1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 127802, -470.0, 0.0, 0.0, 1, "2023/12/22 14:59:59", 1, 10007, "2023/09/15 15:00:00", "ヴルム");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 2002, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 127802, -470.0, 0.0, 6.5, 1, "2023/12/22 14:59:59", 2, 10008, "2023/09/15 15:00:00", "ヴルム");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 2002, 1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 129602, -470.0, 0.0, 0.0, 1, "2024/03/22 14:59:59", 2, 10009, "2023/12/15 15:00:00", "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 2002, 2, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 129602, -470.0, 0.0, 0.0, 1, "2024/03/22 14:59:59", 2, 10010, "2023/12/15 15:00:00", "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 2002, 1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 129701, -470.0, 0.0, 0.0, 1, "2024/03/22 14:59:59", 1, 10011, "2023/12/15 15:00:00", "ネフィ=ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 2002, 2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 129701, -470.0, 0.0, 6.2, 1, "2024/03/22 14:59:59", 2, 10012, "2023/12/15 15:00:00", "ネフィ=ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 2002, 1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 130301, -470.0, 0.0, 3.1, 5, "2024/06/22 14:59:59", 3, 10013, "2024/03/15 15:00:00", "カノン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 2002, 2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 130301, -470.0, 0.0, 6.15, 2, "2024/06/22 14:59:59", 3, 10014, "2024/03/15 15:00:00", "カノン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 2002, 1, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 130401, -470.0, 0.0, 0.0, 2, "2024/06/22 14:59:59", 2, 10015, "2024/03/15 15:00:00", "ナーナ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 2002, 2, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 130401, -470.0, 0.0, 3.35, 1, "2024/06/22 14:59:59", 2, 10016, "2024/03/15 15:00:00", "ナーナ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 2002, 1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 130502, -470.0, 0.0, 0.0, 1, "2024/09/22 14:59:59", 1, 10017, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 2002, 2, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 130502, -470.0, 0.0, 3.18, 1, "2024/09/22 14:59:59", 2, 10018, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 2002, 3, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 130503, -470.0, 0.0, 0.0, 4, "2024/09/22 14:59:59", 4, 10019, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 2002, 1, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 123301, -470.0, 0.0, 4.9, 2, "2024/09/22 14:59:59", 1, 10020, "2024/06/15 15:00:00", "ネア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 2002, 2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 123301, -470.0, 0.0, 4.8, 2, "2024/09/22 14:59:59", 1, 10021, "2024/06/15 15:00:00", "ネア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 2002, 1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 133301, -470.0, 0.0, 4.922, 1, "2024/12/22 14:59:59", 3, 10022, "2024/09/15 15:00:00", "カリザ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 2002, 2, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 133301, -470.0, 0.0, 9.638, 5, "2024/12/22 14:59:59", 3, 10023, "2024/09/15 15:00:00", "カリザ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 2002, 1, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 133401, -470.0, 0.0, 2.88, 2, "2024/12/22 14:59:59", 1, 10024, "2024/09/15 15:00:00", "ミーア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 2002, 2, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 133401, -470.0, 0.0, 4.818, 1, "2024/12/22 14:59:59", 5, 10025, "2024/09/15 15:00:00", "ミーア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 2002, 1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 133002, -470.0, 0.0, 1.78, 1, "2025/03/22 14:59:59", 2, 10026, "2024/12/15 15:00:00", "グレイス");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 2002, 2, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 133002, -470.0, 0.0, 6.15, 7, "2025/03/22 14:59:59", 1, 10027, "2024/12/15 15:00:00", "グレイス");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 2002, 1, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 133102, -470.0, 0.0, 4.28, 2, "2025/03/22 14:59:59", 6, 10028, "2024/12/15 15:00:00", "ヴァイオレット");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 2002, 2, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 133102, -470.0, 0.0, 0.0, 1, "2025/03/22 14:59:59", 1, 10029, "2024/12/15 15:00:00", "ヴァイオレット");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 2002, 1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 136902, -470.0, 0.0, 5.53, 1, "2025/06/23 14:59:59", 2, 10030, "2025/03/15 15:00:00", "ルルィ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 2002, 2, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 136902, -470.0, 0.0, 6.05, 7, "2025/06/23 14:59:59", 9, 10031, "2025/03/15 15:00:00", "ルルィ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 2002, 1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 137001, -470.0, 0.0, 0.0, 1, "2025/06/23 14:59:59", 2, 10032, "2025/03/15 15:00:00", "デュラン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 2002, 2, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 137001, -470.0, 0.0, 0.0, 1, "2025/06/23 14:59:59", 2, 10033, "2025/03/15 15:00:00", "デュラン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 2002, 1, "おう\n好きなもん持ってきな", 135902, -470.0, 0.0, 0.0, 2, "2025/09/23 14:59:59", 2, 10034, "2025/06/16 15:00:00", "サツキ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 2002, 2, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 135902, -470.0, 0.0, 4.935, 6, "2025/09/23 14:59:59", 1, 10035, "2025/06/16 15:00:00", "サツキ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 2002, 1, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 135802, -470.0, 0.0, 7.441, 5, "2025/09/23 14:59:59", 2, 10036, "2025/06/16 15:00:00", "ユキノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 2002, 2, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 135802, -470.0, 0.0, 0.0, 7, "2025/09/23 14:59:59", 7, 10037, "2025/06/16 15:00:00", "ユキノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2002, 1, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 130901, -470.0, 0.0, 2.295, 2, "2025/12/22 14:59:59", 2, 10038, "2025/09/16 15:00:00", "クルル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2002, 2, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 130901, -470.0, 0.0, 6.281, 6, "2025/12/22 14:59:59", 1, 10039, "2025/09/16 15:00:00", "クルル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2002, 1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 137701, -470.0, 0.0, 5.549, 1, "2025/12/22 14:59:59", 2, 10040, "2025/09/16 15:00:00", "ヴォルガーノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2002, 2, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 137701, -470.0, 0.0, 2.64, 6, "2025/12/22 14:59:59", 3, 10041, "2025/09/16 15:00:00", "ヴォルガーノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 2002, 1, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 132801, -470.0, 0.0, 7.642, 4, "2026/03/23 11:59:59", 7, 10042, "2025/12/15 15:00:00", "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 2002, 2, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 132802, -470.0, 0.0, 0.0, 1, "2026/03/23 11:59:59", 1, 10043, "2025/12/15 15:00:00", "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 2002, 1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 134502, -470.0, 0.0, 0.0, 1, "2026/03/23 11:59:59", 1, 10044, "2025/12/15 15:00:00", "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 2002, 2, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 134501, -470.0, 0.0, 3.72, 1, "2026/03/23 11:59:59", 2, 10045, "2025/12/15 15:00:00", "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 2002, 1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 138201, -470.0, 0.0, 4.991, 1, "2026/06/22 11:59:59", 2, 10046, "2026/03/16 12:00:00", "ネフィ＝ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 2002, 2, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 138201, -470.0, 0.0, 3.877, 4, "2026/06/22 11:59:59", 1, 10047, "2026/03/16 12:00:00", "ネフィ＝ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 2002, 1, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 136001, -470.0, 0.0, 1.71, 6, "2026/06/22 11:59:59", 4, 10048, "2026/03/16 12:00:00", "アラクネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 2002, 2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 136001, -470.0, 0.0, 5.32, 2, "2026/06/22 11:59:59", 5, 10049, "2026/03/16 12:00:00", "アラクネ");
